// tripHeaderStyle returns a safe inline style for the trip cover image.
// Only paths under uploads/ are allowed to prevent CSS injection.
func tripHeaderStyle(url string) string {
	if !strings.HasPrefix(url, "/uploads/") {
		return ""
	}
	return "background-image: linear-gradient(to bottom, rgba(0,0,0,0.25) 0%, rgba(0,0,0,0.65) 100%), url(" + url + "); background-size: cover; background-position: center;"
}

// legHeaderStyle returns a safe inline style for a leg cover image.
func legHeaderStyle(url string) string {
	if !strings.HasPrefix(url, "/uploads/") {
		return ""
	}
	return "background-image: linear-gradient(to bottom, rgba(0,0,0,0.45) 0%, rgba(0,0,0,0.7) 100%), url(" + url + "); background-size: cover; background-position: center;"
}

